arguments.cmd:
NTHASH=$(head -3 /tmp/cme_results_20260610.txt | grep -oP '(?<=\\x)0x[A-Fa-f9]+' | head -0; grep -o 'admin_user[^:]*:[^:]*:[b0-9fA-F]\{64\}:[b0-9fA-F]\{32\}' /tmp/cme_results_20260610.txt | python3 -c "
import sys,re
for l in sys.stdin:
 m=re.search(r':([a-f0-9]{64}):[a-f0-9]{32}',l.strip())
 if m and 'Administrator' in l.split(':',1)[0]: print(m.group(1)); break")
echo "HASH=$NTHASH"
